"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[6829],{5502:e=>{e.exports=JSON.parse('{"lang":"es","resources":{"landing":{"meta":{"title":"Linguist \u2013 Extensi\xf3n de traducci\xf3n enfocada en la privacidad para Chrome y Firefox","description":"Extensi\xf3n de navegador para traducir p\xe1ginas web, texto seleccionado y subt\xedtulos. Funciona al instante y permite traducir sin conexi\xf3n a internet."},"navigation":{"features":{"content":"Funciones"},"blog":{"content":"Blog"},"docs":{"content":"Documentaci\xf3n"},"github":{"content":"GitHub"}},"install":{"chrome":"Instalar para Chrome","firefox":"Instalar para Firefox"},"sections":{"hero":{"title":"Traduce cualquier contenido en tu navegador","description":"Linguist es una extensi\xf3n de navegador que traduce texto al instante.\\n\\nTraduce p\xe1ginas web completas, texto seleccionado, subt\xedtulos de Netflix y mensajes privados. Escucha el texto traducido y guarda las traducciones importantes en tu diccionario personal para aprender nuevas palabras, incluso sin conexi\xf3n.\\n\\nLinguist es una alternativa moderna a las extensiones de Google Translate, enfocada en la privacidad. Pru\xe9bala gratis."},"opensource":{"title":"C\xf3digo abierto","content":"Linguist es una extensi\xf3n de traducci\xf3n gratuita y de <0>c\xf3digo abierto</0>. No recopila ni vende los datos de los usuarios.\\n\\nPuedes <1>hacer una donaci\xf3n</1> para apoyar a Linguist y ayudarnos a mantener nuestra independencia y alta calidad.\\n\\nComparte Linguist en redes sociales para ayudar a otras personas a descubrirla."},"support":{"title":"Soporte","content":"Si tienes preguntas, cont\xe1ctanos <0/>.\\nSi encuentras un error y tienes una cuenta en GitHub, por favor <1>abre un reporte</1>."},"createdBy":{"content":"Creado por <0/>."}},"features":{"title":"Funciones","items":{"offlineTranslation":{"title":"Traducci\xf3n sin conexi\xf3n y privacidad","content":"Traduce texto directamente en tu dispositivo con el traductor sin conexi\xf3n integrado. Tu texto se mantiene privado y no se env\xeda a trav\xe9s de internet.\\n\\nActiva esta funci\xf3n en la p\xe1gina de opciones para mantener la privacidad de tus traducciones al trabajar con correos electr\xf3nicos, documentos o mensajes personales.\\n\\nEl traductor sin conexi\xf3n tambi\xe9n te permite traducir p\xe1ginas sin conexi\xf3n a internet, lo cual es especialmente \xfatil cuando viajas."},"fullPageTranslation":{"title":"Traducci\xf3n de p\xe1ginas completas","content":"Traducci\xf3n r\xe1pida y de alta calidad de p\xe1ginas completas con solo unos clics.\\n\\nUsa un atajo de teclado para traducir al instante. Pasa el cursor sobre el texto traducido para ver el original. Traduce incluso p\xe1ginas privadas protegidas por contrase\xf1as o muros de pago.\\n\\nConfigura reglas de traducci\xf3n autom\xe1tica seg\xfan el idioma o el dominio de la p\xe1gina.\\n\\nLinguist modifica la p\xe1gina lo m\xednimo indispensable: solo cambia los nodos de texto para conservar el dise\xf1o original y la experiencia de uso.\\n\\nActiva la traducci\xf3n en tiempo real para reuniones en varios idiomas en Zoom, Google Meet y Microsoft Teams."},"selectedTextTranslation":{"title":"Traducci\xf3n de texto seleccionado","content":"\xbfEncuentras palabras desconocidas al leer un art\xedculo en l\xednea?\\nSimplemente selecciona el texto en la p\xe1gina y haz clic en el bot\xf3n de traducir.\\n\\nEscucha tanto el texto original como el traducido, y guarda las traducciones en tu diccionario para repasarlas m\xe1s tarde."},"textTranslation":{"title":"Traducci\xf3n r\xe1pida de texto","content":"\xbfNecesitas traducir algo r\xe1pidamente? Haz clic en el icono de Linguist y escribe tu texto.\\n\\nNo es necesario cambiar de pesta\xf1a ni abrir sitios web de traducci\xf3n. Traduce directamente en tu navegador usando el servicio que prefieras."},"knowledgeBase":{"title":"Crea tu propia base de conocimientos","content":"Cada traducci\xf3n se guarda en tu historial, y puedes a\xf1adir las m\xe1s importantes a tu diccionario personal. Busca en tu diccionario y en tu historial de traducci\xf3n en cualquier momento.\\n\\nNo perder\xe1s nada, incluso durante largas sesiones de investigaci\xf3n o estudio.\\n\\nEl diccionario funciona sin conexi\xf3n, lo que hace que Linguist sea ideal para estudiantes de idiomas y viajeros que necesitan acceso constante a sus listas de palabras."},"customTranslators":{"title":"Traductores personalizados","content":"Linguist te permite elegir qu\xe9 servicio de traducci\xf3n utilizar.\\n\\nEs compatible con proveedores populares como Google, Yandex y Microsoft, con m\xe1s de 100 idiomas disponibles.\\n\\nSi el servicio que necesitas no est\xe1 incluido, puedes a\xf1adirlo como un <0>traductor personalizado</0>.\\n\\nLos traductores personalizados te permiten integrar cualquier sistema de traducci\xf3n: desde servicios modernos basados en IA como ChatGPT, DeepL, DeepSeek y Gemini, hasta traductores locales que se ejecutan en tu dispositivo, como Ollama o LibreTranslate."}}},"faq":{"title":"Preguntas frecuentes","items":{"whatIsLinguist":{"title":"\xbfQu\xe9 es Linguist?","content":"Linguist es una extensi\xf3n de traducci\xf3n para Chrome y Firefox enfocada en la privacidad.\\n\\nTe permite traducir p\xe1ginas web completas, texto seleccionado, subt\xedtulos y mensajes directamente en tu navegador, sin tener que cambiar a sitios web de traducci\xf3n externos."},"whyLinguist":{"title":"\xbfPor qu\xe9 usar Linguist?","content":"Existen muchas extensiones de navegador para traducir p\xe1ginas web, y algunos navegadores incluso incluyen traductores integrados. Entonces, \xbfpor qu\xe9 usar Linguist?\\n\\nLa mayor\xeda de los traductores integrados y las extensiones de traducci\xf3n ofrecen poca flexibilidad. Muchos dependen de un \xfanico proveedor, como Google Translate o Microsoft Bing, mientras que Firefox ofrece su propio traductor sin conexi\xf3n. En la mayor\xeda de los casos, no puedes elegir el servicio que mejor se adapte a tus necesidades.\\n\\nSi la calidad de la traducci\xf3n no es suficiente para lo que buscas, o si enviar textos privados a servicios de terceros no es una opci\xf3n, muchas herramientas te dejan sin una buena alternativa.\\n\\nAdem\xe1s, muchas herramientas se centran en una sola tarea. Algunas traducen p\xe1ginas completas, mientras que otras solo traducen el texto seleccionado.\\n\\nAl mismo tiempo, algunas extensiones de traducci\xf3n est\xe1n dise\xf1adas principalmente para ganar dinero. Funciones como el historial de traducci\xf3n o los diccionarios personales pueden requerir una suscripci\xf3n, y a veces incluso caracter\xedsticas b\xe1sicas como el modo oscuro se consideran opciones de pago.\\n\\nLinguist adopta un enfoque diferente. Est\xe1 dise\xf1ada como una herramienta de traducci\xf3n pr\xe1ctica. Puedes elegir el servicio de traducci\xf3n que mejor te funcione, cambiar de proveedor o a\xf1adir tus propios traductores personalizados.\\n\\nLinguist tambi\xe9n re\xfane todo en un solo lugar: traduce p\xe1ginas web completas, texto seleccionado, subt\xedtulos y mensajes, mientras guardas las traducciones importantes en tu historial y en tu diccionario personal."},"theLinguistLogo":{"title":"\xbfPor qu\xe9 el logo de Linguist es la Torre de Babel?","content":"El logo de Linguist est\xe1 inspirado en la <wiki>Torre de Babel</wiki>, una de las historias m\xe1s antiguas sobre el lenguaje y la comunicaci\xf3n.\\n\\nSeg\xfan la historia, las personas hablaban un solo idioma e intentaron construir una torre que llegara al cielo. La torre nunca se termin\xf3 y la humanidad se dispers\xf3 en muchos idiomas. Desde entonces, las diferencias de idioma a menudo han dificultado la comunicaci\xf3n.\\n\\nLinguist se cre\xf3 para ayudar a resolver este problema.\\n\\nLa Torre de Babel en el logo es un recordatorio de esa historia: muchos idiomas, muchas culturas y el esfuerzo humano constante por entendernos. Linguist ayuda a superar esas barreras al hacer que la traducci\xf3n sea sencilla, flexible y accesible directamente en tu navegador.\\n\\nEl logo tambi\xe9n refleja el esp\xedritu del proyecto. Linguist no es solo otra interfaz para \\"Google Translate\\". Est\xe1 desarrollada por personas a las que les importan los idiomas, la privacidad y la tecnolog\xeda abierta. La Torre de Babel representa la curiosidad, el aprendizaje y la idea de que las diferencias de idioma deber\xedan unir a las personas en lugar de separarlas."},"imageTranslation":{"title":"\xbfPor qu\xe9 Linguist no traduce el texto de las im\xe1genes?","content":"Linguist se centra en ofrecer funciones de traducci\xf3n fiables y de alta calidad.\\n\\nHemos investigado diferentes m\xe9todos para traducir el texto dentro de las im\xe1genes. Por el momento, la mayor\xeda de las soluciones disponibles no ofrecen resultados consistentes, especialmente cuando se ejecutan directamente en el navegador, lo cual es fundamental para mantener la privacidad del usuario.\\n\\nPor este motivo, Linguist no incluye actualmente la traducci\xf3n de im\xe1genes. Preferimos no lanzar funciones que no cumplan con nuestros est\xe1ndares de calidad.\\n\\nSi en el futuro encontramos una forma fiable y respetuosa con la privacidad de implementar la traducci\xf3n de im\xe1genes, estaremos encantados de a\xf1adirla."},"howTranslatePages":{"title":"\xbfC\xf3mo traduce Linguist las p\xe1ginas web?","content":"Linguist puede traducir p\xe1ginas web completas con solo unos clics. Puedes iniciar la traducci\xf3n de la p\xe1gina usando el bot\xf3n de la extensi\xf3n o un atajo de teclado.\\n\\nEl texto original siempre permanece accesible. Pasa el cursor sobre el texto traducido para ver el original."},"offlineTranslation":{"title":"\xbfPuede Linguist traducir p\xe1ginas sin conexi\xf3n?","content":"S\xed. Linguist incluye un traductor sin conexi\xf3n integrado que te permite traducir texto sin enviar datos a trav\xe9s de internet.\\n\\nEsto ayuda a proteger tu privacidad y te permite traducir contenido incluso sin conexi\xf3n a internet."},"privacy":{"title":"\xbfLinguist es privado?","content":"S\xed. Linguist est\xe1 dise\xf1ado pensando en la privacidad.\\n\\nLa extensi\xf3n no recopila ni vende los datos de los usuarios. Al usar el <offline-translator>traductor sin conexi\xf3n</offline-translator>, las traducciones se procesan \xedntegramente en tu dispositivo."},"supportedBrowsers":{"title":"\xbfQu\xe9 navegadores son compatibles con Linguist?","content":"Linguist est\xe1 disponible para Chrome y Firefox. Tambi\xe9n funciona en otros navegadores basados en Chromium que admiten extensiones de Chrome.\\n\\nLinguist tambi\xe9n funciona en navegadores de Android que admiten extensiones, como Firefox para Android y algunos navegadores basados en Chromium."},"selectedText":{"title":"\xbfPuede Linguist traducir texto seleccionado?","content":"S\xed. Simplemente selecciona el texto en cualquier p\xe1gina web y usa el bot\xf3n de traducir para hacerlo al instante.\\n\\nTambi\xe9n puedes escuchar la traducci\xf3n y guardarla en tu diccionario personal."},"customTranslators":{"title":"\xbfPuedo usar mi propio servicio de traducci\xf3n?","content":"S\xed. Linguist es compatible con <custom-translator>traductores personalizados</custom-translator>, lo que te permite integrar servicios de traducci\xf3n adicionales.\\n\\nPuedes conectar APIs externas o sistemas de traducci\xf3n locales como <libre-translate>LibreTranslate</libre-translate> u <ollama>Ollama</ollama>."},"isFree":{"title":"\xbfLinguist es gratis?","content":"S\xed. Linguist es completamente gratis y de <linguist>c\xf3digo abierto</linguist>.\\n\\nEl proyecto se mantiene gracias a la comunidad, y de forma opcional puedes <donations>apoyarlo con una donaci\xf3n</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);